function summarize(t2) {
  const s = {
    id: t2.id,
    kind: t2.kind,
    name: t2.name,
    requires: t2.requires,
    available: t2.available
  };
  if (!t2.available && t2.reason !== void 0) s.reason = t2.reason;
  return s;
}
function listTemplates(all, opts = {}) {
  const scoped = opts.kind ? all.filter((t2) => t2.kind === opts.kind) : all;
  const availableEntries = scoped.filter((t2) => t2.available);
  const unavailableEntries = scoped.filter((t2) => !t2.available);
  const listing = opts.includeUnavailable ? scoped : availableEntries;
  return {
    templates: listing.map(summarize),
    available: availableEntries.length,
    unavailableCount: unavailableEntries.length,
    unavailable: unavailableEntries.map((t2) => ({ id: t2.id, name: t2.name, reason: t2.reason ?? "" }))
  };
}
function getTemplate(all, id) {
  return all.find((t2) => t2.id === id);
}

