    "kind": "block",
    "name": "Chat Tool Calls Statuses",
    "code": "// Copyright (c) Meta Platforms, Inc. and affiliates.\\n\\n'use client';\\n\\nimport {ChatToolCalls} from '@astryxdesign/core/Chat';\\n\\nexport default function ChatToolCallsStatuses() {\\n  return (\\n    <ChatToolCalls\\n      defaultIsExpanded\\n      calls={[\\n        {\\n          key: 'pending',\\n          name: 'bash',\\n          target: 'yarn build',\\n          status: 'pending',\\n        },\\n        {\\n          key: 'running',\\n          name: 'bash',\\n          target: 'yarn test',\\n          status: 'running',\\n        },\\n        {\\n          key: 'complete',\\n          name: 'edit',\\n          target: 'src/App.tsx',\\n          status: 'complete',\\n          duration: '120ms',\\n          additions: 8,\\n          deletions: 2,\\n        },\\n        {\\n          key: 'error',\\n          name: 'bash',\\n          target: 'yarn lint',\\n          status: 'error',\\n          duration: '0.8s',\\n          errorMessage: '3 lint errors found',\\n        },\\n      ]}\\n    />\\n  );\\n}\\n",
